class CanarySystem:
    # Mixes decoy 'canary' credentials in with real ones. Accessing a canary
    # trips the kill switch and raises an alarm; real keys return ok.
    def __init__(self, kill_switch):
        self.kill_switch = kill_switch
        self.real = {'db_password': 'real-1', 'api_key': 'real-2'}
        self.canaries = {'aws_root_key', 'prod_master_token'}
        self.store = dict(self.real)
        for c in self.canaries:
            self.store[c] = f'decoy-{c}'
        self.alarms = []
